  {
    icon: Sparkles,
    title: "Nhận kết quả & hiểu bài",
    description:
      "Nhận kết quả phân tích kèm giải thích chi tiết — đủ để bạn tự tin trình bày và bảo vệ luận văn.",
  },
];

export default function HowItWorksSection\(\) {
  const lineRef = useRef<SVGLineElement>\(null\);

  useEffect\(\(\) => {
    const line = lineRef.current;
    if \(!line\) return;

    const observer = new IntersectionObserver\(
      \([entry]\) => {
        if \(entry.isIntersecting\) {
          line.style.transition = "stroke-dashoffset 1.5s ease-in-out";
          line.style.strokeDashoffset = "0";
          observer.disconnect\(\);
        }
      },
      { threshold: 0.3 }
    \);

    observer.observe\(line\);
    return \(\) => observer.disconnect\(\);
  }, []\);

  return \(
    <section id={SECTION_IDS.howItWorks} className="relative py-20 md:py-32 section-padding">
      <div className="max-w-4xl mx-auto">
        <FadeInWhenVisible>
          <SectionHeading
